from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager, jwt_required, create_access_token, get_raw_jwt
from datetime import timedelta
import jwt
import hashlib
import os

app = Flask(__name__)
app.config["JWT_SECRET_KEY"] = "your-secret-key"  # Replace with your own secret key
jwt = JWTManager(app)

def sha256_password_hash(password):
    return hashlib.sha256(password.encode()).hexdigest()

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    if not data or not data.get('password'):
        return jsonify({"error": "Invalid data provided"}), 400

    password = sha256_password_hash(data["password"])
    users[data["username"]] = password
    return jsonify({"message": "User registered successfully"}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({"error": "Invalid data provided"}), 400

    if data["username"] not in users:
        return jsonify({"error": "Incorrect username"}), 401

    password = sha256_password_hash(data["password"])
    if users[data["username"]] != password:
        return jsonify({"error": "Incorrect password"}), 401

    access_token = create_access_token(identity=data["username"])
    return jsonify(access_token=access_token)

@app.route('/protected')
@jwt_required()
def protected():
    username = get_raw_jwt()["sub"]  # Get the user's username from the token
    return jsonify({"user": username})

users = {}  # User registry for this example
if not os.path.exists("jwt_secret_key"):
    with open("jwt_secret_key", "w") as f:
        f.write(app.config["JWT_SECRET_KEY"])

if __name__ == "__main__":
    app.run()